## Test Patterns

### Microservice Test (TCP)

```typescript
import { ClientProxy, ClientProxyFactory, Transport } from '@nestjs/microservices';
import { YourCommands } from '@optimistic-tanuki/constants';
import { firstValueFrom } from 'rxjs';

describe('Your Service E2E', () => {
  let client: ClientProxy;

  beforeAll(async () => {
    client = ClientProxyFactory.create({
      transport: Transport.TCP,
      options: {
        host: '127.0.0.1',
        port: YOUR_PORT,
      },
    });
    await client.connect();
  });

  afterAll(async () => {
    await client.close();
  });

  it('should test command', async () => {
    const result = await firstValueFrom(client.send({ cmd: YourCommands.COMMAND }, payload));
    expect(result).toBeDefined();
  });
});
```

### Gateway Test (HTTP)

```typescript
import axios from 'axios';

describe('Endpoint Tests', () => {
  const api = axios.create({
    baseURL: 'http://localhost:3000/api',
